  "day": "2",
  "heading": "Trek from Karchi to Akhrotghetta",
  "sub_heading": "Trek Distance: 2.75 km | Duration: 5-6 hours | Altitude gain: 7,785 ft to 9,264 ft",
  "details": ""
}

{
  "day": "3",
  "heading": "Trek from Akhrotghetta to Khullara",
  "sub_heading": "Trek Distance: 2.5 km | Trek Duration: 4-5 hours | Altitude gain: 9,264 ft to 11,014 ft",
  "details": ""
}

{
  "day": "4",
  "heading": "Trek from Khullara to Tali via Kuari Pass",
  "sub_heading": "Trek Distance: 7.65 km | Trek Duration: 8-9 hours | Altitude gain and loss: 11,014 ft to 10,990 ft via 12,516 ft",
  "details": ""
}

{
  "day": "5",
  "heading": "Trek from Tali to Auli. Drive to Karchi / Dhak",
  "sub_heading": "Trek Distance: 8.10 km | Trek Duration: 7-8 hours | Altitude loss: 10,990 ft to 9,390 ft\nDrive Distance: 21 km | Drive duration: 1 hr",
  "details": ""
}

{
  "day": "6",
  "heading": "Depart from Dhak / Karchi and reach Rishikesh",
  "sub_heading": "Drive distance: 255 km | Drive Duration: 9-10 hours | Drop off point for Indiahikes Trekkers: Live Free Hostel, Rishikesh | Drop off Time: 6 pm",
  "details": "You are expected to be back in Rishikesh by 6 p.m. Cost of the cab: Rs 1500 (additional 5% GST) per trekker (one-way). (This includes the extra charges from Auli to Dhak).  Please pre-book your transport through the dashboard before your trek.\nPlease note: The trek itinerary and campsites can change in case of extreme weather such as rainfall and snowfall. The section of Gorson Bugyal becomes inaccessible which is why we need to re-route."
}
